const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.json({ limit: '10mb' }));

const client = new Client({
  node: process.env.ELASTICSEARCH_URL || 'http://localhost:9200'
});

function buildBoolQuery(searchParams) {
  const boolQuery = {
    must: [],
    should: [],
    filter: [],
    must_not: []
  };

  if (searchParams.text) {
    boolQuery.must.push({
      multi_match: {
        query: searchParams.text,
        fields: searchParams.fields || ['*'],
        type: searchParams.matchType || 'best_fields',
        fuzziness: searchParams.fuzziness || 'AUTO'
      }
    });
  }

  if (searchParams.exactMatch) {
    Object.entries(searchParams.exactMatch).forEach(([field, value]) => {
      boolQuery.filter.push({ term: { [field]: value } });
    });
  }

  if (searchParams.range) {
    Object.entries(searchParams.range).forEach(([field, rangeConfig]) => {
      boolQuery.filter.push({ range: { [field]: rangeConfig } });
    });
  }

  if (searchParams.exists) {
    searchParams.exists.forEach(field => {
      boolQuery.filter.push({ exists: { field } });
    });
  }

  if (searchParams.prefix) {
    Object.entries(searchParams.prefix).forEach(([field, value]) => {
      boolQuery.must.push({ prefix: { [field]: value } });
    });
  }

  if (searchParams.wildcard) {
    Object.entries(searchParams.wildcard).forEach(([field, value]) => {
      boolQuery.must.push({ wildcard: { [field]: value } });
    });
  }

  if (searchParams.regexp) {
    Object.entries(searchParams.regexp).forEach(([field, value]) => {
      boolQuery.must.push({ regexp: { [field]: value } });
    });
  }

  if (searchParams.mustNot) {
    Object.entries(searchParams.mustNot).forEach(([field, value]) => {
      boolQuery.must_not.push({ term: { [field]: value } });
    });
  }

  if (searchParams.should) {
    searchParams.should.forEach(condition => {
      if (condition.match) {
        boolQuery.should.push({ match: condition.match });
      } else if (condition.term) {
        boolQuery.should.push({ term: condition.term });
      }
    });
    if (searchParams.minimumShouldMatch) {
      boolQuery.minimum_should_match = searchParams.minimumShouldMatch;
    }
  }

  const cleanedBool = {};
  Object.entries(boolQuery).forEach(([key, value]) => {
    if (Array.isArray(value) && value.length > 0) {
      cleanedBool[key] = value;
    } else if (!Array.isArray(value)) {
      cleanedBool[key] = value;
    }
  });

  return Object.keys(cleanedBool).length > 0 ? { bool: cleanedBool } : { match_all: {} };
}

function buildScriptScoreQuery(baseQuery, scriptConfig) {
  if (!scriptConfig || !scriptConfig.source) {
    return baseQuery;
  }

  return {
    script_score: {
      query: baseQuery,
      script: {
        source: scriptConfig.source,
        lang: scriptConfig.lang || 'painless',
        params: scriptConfig.params || {}
      },
      min_score: scriptConfig.minScore,
      boost: scriptConfig.boost
    }
  };
}

function buildFunctionScoreQuery(baseQuery, functionConfig) {
  if (!functionConfig) {
    return baseQuery;
  }

  const functionScore = {
    query: baseQuery,
    boost_mode: functionConfig.boostMode || 'multiply',
    score_mode: functionConfig.scoreMode || 'multiply',
    max_boost: functionConfig.maxBoost,
    min_score: functionConfig.minScore
  };

  if (functionConfig.functions) {
    functionScore.functions = functionConfig.functions.map(func => {
      const scoreFunc = {};
      
      if (func.filter) {
        scoreFunc.filter = func.filter;
      }
      
      if (func.weight) {
        scoreFunc.weight = func.weight;
      }
      
      if (func.scriptScore) {
        scoreFunc.script_score = {
          script: {
            source: func.scriptScore.source,
            lang: func.scriptScore.lang || 'painless',
            params: func.scriptScore.params || {}
          }
        };
      }
      
      if (func.fieldValueFactor) {
        scoreFunc.field_value_factor = func.fieldValueFactor;
      }
      
      if (func.randomScore) {
        scoreFunc.random_score = func.randomScore;
      }
      
      if (func.decayFunction) {
        const decayType = func.decayFunction.type || 'gauss';
        scoreFunc[decayType] = {
          [func.decayFunction.field]: {
            origin: func.decayFunction.origin,
            scale: func.decayFunction.scale,
            offset: func.decayFunction.offset,
            decay: func.decayFunction.decay
          }
        };
      }
      
      return scoreFunc;
    });
  }

  if (functionConfig.scriptScore && !functionConfig.functions) {
    functionScore.script_score = {
      script: {
        source: functionConfig.scriptScore.source,
        lang: functionConfig.scriptScore.lang || 'painless',
        params: functionConfig.scriptScore.params || {}
      }
    };
  }

  return { function_score: functionScore };
}

function buildAggregations(aggConfig) {
  if (!aggConfig) {
    return undefined;
  }

  const aggregations = {};

  Object.entries(aggConfig).forEach(([name, config]) => {
    if (config.terms) {
      aggregations[name] = { terms: config.terms };
    } else if (config.range) {
      aggregations[name] = { range: config.range };
    } else if (config.dateHistogram) {
      aggregations[name] = { date_histogram: config.dateHistogram };
    } else if (config.histogram) {
      aggregations[name] = { histogram: config.histogram };
    } else if (config.stats) {
      aggregations[name] = { stats: config.stats };
    } else if (config.avg) {
      aggregations[name] = { avg: config.avg };
    } else if (config.sum) {
      aggregations[name] = { sum: config.sum };
    } else if (config.cardinality) {
      aggregations[name] = { cardinality: config.cardinality };
    } else if (config.nested) {
      aggregations[name] = { nested: config.nested };
      if (config.aggs) {
        aggregations[name].aggs = buildAggregations(config.aggs);
      }
    }

    if (config.aggs && !config.nested) {
      aggregations[name].aggs = buildAggregations(config.aggs);
    }
  });

  return aggregations;
}

app.post('/api/search', async (req, res) => {
  try {
    const {
      index,
      searchParams,
      scriptScore,
      functionScore,
      aggregations,
      sort,
      from = 0,
      size = 10,
      source,
      highlight,
      trackTotalHits = true
    } = req.body;

    if (!index) {
      return res.status(400).json({ error: 'Index parameter is required' });
    }

    let query = buildBoolQuery(searchParams || {});

    if (scriptScore) {
      query = buildScriptScoreQuery(query, scriptScore);
    } else if (functionScore) {
      query = buildFunctionScoreQuery(query, functionScore);
    }

    const searchBody = {
      query,
      from,
      size,
      track_total_hits: trackTotalHits
    };

    if (sort) {
      searchBody.sort = sort;
    }

    if (source !== undefined) {
      searchBody._source = source;
    }

    if (highlight) {
      searchBody.highlight = highlight;
    }

    const aggs = buildAggregations(aggregations);
    if (aggs) {
      searchBody.aggs = aggs;
    }

    const result = await client.search({
      index,
      body: searchBody
    });

    res.json({
      total: result.hits.total,
      hits: result.hits.hits,
      aggregations: result.aggregations,
      took: result.took
    });

  } catch (error) {
    console.error('Search error:', error);
    res.status(500).json({
      error: 'Search failed',
      message: error.message,
      details: error.meta?.body?.error
    });
  }
});

